const now = new Date();
const firstDay = new Date(now.getFullYear(), now.getMonth(), 1, 0, 0, 0, 0);
now.setHours(23, 59, 59, 999);

const starttmp = Math.floor(firstDay.getTime() / 1000);
const endtmp = Math.floor(now.getTime() / 1000);

return [{
  json: {
    starttmp,
    endtmp,
    fechaDesde: firstDay.toLocaleDateString('es-ES'),
    fechaHasta: now.toLocaleDateString('es-ES')
  }
}];

const items = $input.all();
const fechaDesde = items[0]?.json?.fechaDesde
  ?? $('Calcular rango última semana').first().json.fechaDesde;
const fechaHasta = items[0]?.json?.fechaHasta
  ?? $('Calcular rango última semana').first().json.fechaHasta;

let albaranes = [];

for (const item of items) {
  const data = item.json;
  if (Array.isArray(data)) {
    albaranes = data;
    break;
  }
  if (data.id) {
    albaranes.push(data);
  }
}

if (albaranes.length === 0) {
  return [{
    json: {
      totalAlbaranes: 0,
      fechaDesde,
      fechaHasta,
      mensaje: 'No se encontraron albaranes en la última semana',
      albaranes: []
    }
  }];
}

const fmt = (ts) => {
  if (!ts) return '—';
  const d = new Date(ts * 1000);
  return d.toLocaleDateString('es-ES', {
    day: '2-digit', month: '2-digit', year: 'numeric'
  });
};

const fmtMoney = (n) => Number(n || 0).toLocaleString('es-ES', {
  minimumFractionDigits: 2,
  maximumFractionDigits: 2
}) + ' €';

let totalImporte = 0;

const resumen = albaranes.map(a => {
  const total = Number(a.total || a.subtotal || 0);
  totalImporte += total;
  return {
    id: a.id,
    numero: a.docNumber || a.num || '—',
    fecha: fmt(a.date),
    contacto: a.contactName || a.contact?.name || '—',
    contactId: a.contactId || a.contact?.id || null,
    estado: a.status || '—',
    subtotal: fmtMoney(a.subtotal),
    impuestos: fmtMoney(a.tax),
    total: fmtMoney(a.total),
    numLineas: Array.isArray(a.items) ? a.items.length : 0,
    notas: a.notes || ''
  };
});

return [{
  json: {
    totalAlbaranes: albaranes.length,
    importeTotal: fmtMoney(totalImporte),
    fechaDesde,
    fechaHasta,
    albaranes: resumen
  }
}];

const data = $input.first().json;
return [{
  json: {
    totalAlbaranes: 0,
    fechaDesde: data.fechaDesde,
    fechaHasta: data.fechaHasta,
    mensaje: 'No se encontraron albaranes de ventas en la última semana'
  }
}];
